// Normaliza entrada: CPF só dígitos, valor para número (ponto decimal), vencimento = hoje+3
const body = $input.first().json.body || $input.first().json;
const cpf = String(body.cpf || '').replace(/\D/g, '');
// valor_cobrar pode vir como '123,45' (pt-BR) -> 123.45
const valor = Number(String(body.valor_cobrar || '0').replace(/\./g, '').replace(',', '.'));

const d = new Date();
d.setDate(d.getDate() + 3);
const dueDate = d.toISOString().split('T')[0];

return [{ json: { cpf, nome: body.nome || 'Cliente', valor, dueDate } }];

// Monta a resposta para o Typebot com o Pix copia-e-cola e o link da fatura
const qr = $input.first().json;
const pagamento = $('Asaas — Criar Cobrança Pix').first().json;

return [{ json: {
  data: {
    pix_copia_cola: qr.payload || '(indisponível — use o link da fatura)',
    link_fatura: pagamento.invoiceUrl || pagamento.bankSlipUrl || '',
    payment_id: pagamento.id || '',
    valor: pagamento.value || 0,
    qr_base64: qr.encodedImage || ''
  }
} }];
